// eqAcc sets m to an eq table at q and then adds it to e.
// m <- m[0] · eq(q, -).
// e <- e + m
func (r *resources) eqAcc(e, m polynomial.MultiLin, q []small_rational.SmallRational) {
	n := len(q)

	// At the end of each iteration, m(h₁, ..., hₙ) = m[0] · eq(q₁, ..., qᵢ₊₁, h₁, ..., hᵢ₊₁)
	for i := range q { // 1-based in comments: q[i] = qᵢ₊₁
		// go through all assignments of (b₁, ..., bᵢ) ∈ {0,1}ⁱ
		const threshold = 1 << 6
		k := 1 << i
		if k < threshold {
			for j := 0; j < k; j++ {
				j0 := j << (n - i)    // bᵢ₊₁ = 0
				j1 := j0 + 1<<(n-1-i) // bᵢ₊₁ = 1

				m[j1].Mul(&q[i], &m[j0])  // m(b₁,...,bᵢ,1) = m(b₁,...,bᵢ) · qᵢ₊₁
				m[j0].Sub(&m[j0], &m[j1]) // m(b₁,...,bᵢ,0) = m(b₁,...,bᵢ) · (1 - qᵢ₊₁)
			}
		} else {
			r.workers.Submit(k, func(start, end int) {
				for j := start; j < end; j++ {
					j0 := j << (n - i)    // bᵢ₊₁ = 0
					j1 := j0 + 1<<(n-1-i) // bᵢ₊₁ = 1

					m[j1].Mul(&q[i], &m[j0])  // m(b₁,...,bᵢ,1) = m(b₁,...,bᵢ) · qᵢ₊₁
					m[j0].Sub(&m[j0], &m[j1]) // m(b₁,...,bᵢ,0) = m(b₁,...,bᵢ) · (1 - qᵢ₊₁)
				}
			}, 1024).Wait()
		}
	}
	r.workers.Submit(len(e), func(start, end int) {
		for i := start; i < end; i++ {
			e[i].Add(&e[i], &m[i])
		}
	}, 512).Wait()
}

// zeroCheckBase holds the fields and initialization logic common to both
// zeroCheckClaims and singleSourceZeroCheckClaims.
type zeroCheckBase struct {
	foldingCoeff       small_rational.SmallRational
	levelI             int
	resources          *resources
	input              []polynomial.MultiLin // UniqueGateInputs order
	inputIndices       [][]int               // [wireInLevel][gateInputJ] → index in input
	gateEvaluatorPools []*gateEvaluatorPool
}

func (c *zeroCheckBase) varsNum() int {
	return c.resources.nbVars
}

// proveFinalEval records the outgoing eval point, folds the last variable,
// collects the unique input evaluations, and releases all pooled memory.
// extraPolys is the level-type-specific slice (eqs or suffixEq) to dump.
func (c *zeroCheckBase) proveFinalEval(r []small_rational.SmallRational, extraPolys []polynomial.MultiLin) []small_rational.SmallRational {
	c.resources.outgoingEvalPoints[c.levelI] = [][]small_rational.SmallRational{r}
	evaluations := make([]small_rational.SmallRational, len(c.input))
	for i := range c.input {
		c.input[i].Fold(r[len(r)-1])
		evaluations[i] = c.input[i][0]
	}
	for i := range c.input {
		c.resources.memPool.Dump(c.input[i])
	}
	for i := range extraPolys {
		c.resources.memPool.Dump(extraPolys[i])
	}
	for _, pool := range c.gateEvaluatorPools {
		pool.dumpAll()
	}
	return evaluations
}

// init derives the folding coefficient, clones the input multilinears,
// and builds gate evaluator pools — the steps common to all sumcheck-family provers.
func (c *zeroCheckBase) init(r *resources, levelI int) {
	c.levelI = levelI
	c.resources = r
	level := r.schedule[levelI]
	if level.NbClaims() >= 2 {
		c.foldingCoeff = r.transcript.getChallenge()
	}

	uniqueInputs, inputIndices := r.circuit.InputMapping(level)
	c.input = make([]polynomial.MultiLin, len(uniqueInputs))
	for i, inW := range uniqueInputs {
		c.input[i] = r.memPool.Clone(r.assignment[inW])
	}
	c.inputIndices = inputIndices

	nbWires := 0
	for _, group := range level.ClaimGroups() {
		nbWires += len(group.Wires)
	}
	c.gateEvaluatorPools = make([]*gateEvaluatorPool, nbWires)
	levelWireI := 0
	for _, group := range level.ClaimGroups() {
		for _, wI := range group.Wires {
			wire := r.circuit[wI]
			gate := wire.Gate.Evaluate
			if wire.IsInput() {
				gate = gkrcore.IdentityBytecode()
			}
			c.gateEvaluatorPools[levelWireI] = newGateEvaluatorPool(gate, len(inputIndices[levelWireI]), &r.memPool)
			levelWireI++
		}
	}
}

func (r *resources) proveSumcheckLevel(levelI int) sumcheckProof {
	var claims zeroCheckClaims
	claims.init(r, levelI)

	level := r.schedule[levelI]
	eqLength := 1 << r.nbVars
	claims.eqs = make([]polynomial.MultiLin, len(claims.gateEvaluatorPools))
	var alpha small_rational.SmallRational
	alpha.SetOne()
	levelWireI := 0
	for _, group := range level.ClaimGroups() {
		nbSources := len(group.ClaimSources)

		groupEq := polynomial.MultiLin(r.memPool.Make(eqLength))
		groupEq[0].Set(&alpha)
		groupEq.Eq(r.outgoingEvalPoints[group.ClaimSources[0].Level][group.ClaimSources[0].OutgoingClaimIndex])

		if nbSources > 1 {
			newEq := polynomial.MultiLin(r.memPool.Make(eqLength))
			aI := alpha
			for k := 1; k < nbSources; k++ {
				aI.Mul(&aI, &claims.foldingCoeff)
				newEq[0].Set(&aI)
				r.eqAcc(groupEq, newEq, r.outgoingEvalPoints[group.ClaimSources[k].Level][group.ClaimSources[k].OutgoingClaimIndex])
			}
			r.memPool.Dump(newEq)
		}

		var stride small_rational.SmallRational
		stride.Set(&claims.foldingCoeff)
		for range nbSources - 1 {
			stride.Mul(&stride, &claims.foldingCoeff)
		}

		claims.eqs[levelWireI] = groupEq
		levelWireI++
		alpha.Mul(&alpha, &stride)

		for w := 1; w < len(group.Wires); w++ {
			claims.eqs[levelWireI] = polynomial.MultiLin(r.memPool.Make(eqLength))
			r.workers.Submit(eqLength, func(start, end int) {
				for i := start; i < end; i++ {
					claims.eqs[levelWireI][i].Mul(&claims.eqs[levelWireI-1][i], &stride)
				}
			}, 512).Wait()
			levelWireI++
			alpha.Mul(&alpha, &stride)
		}
	}

	return sumcheckProve(&claims, &r.transcript)
}

// verifyLevelSetup derives the folding coefficient, collects all claimed wire
// evaluations from the proof or the initial assignment, computes the batched
// claimed sum, and builds the lazy-claims object shared by both verifiers.
func (r *resources) verifyLevelSetup(levelI int, proof Proof) (small_rational.SmallRational, *zeroCheckLazyClaims) {
	level := r.schedule[levelI]
	var foldingCoeff small_rational.SmallRational
	if level.NbClaims() >= 2 {
		foldingCoeff = r.transcript.getChallenge()
	}

	initialChallengeI := len(r.schedule)
	claimedEvals := make(polynomial.Polynomial, 0, level.NbClaims())
	for _, group := range level.ClaimGroups() {
		for _, wI := range group.Wires {
			for claimI, src := range group.ClaimSources {
				if src.Level == initialChallengeI {
					claimedEvals = append(claimedEvals, r.assignment[wI].Evaluate(r.outgoingEvalPoints[src.Level][src.OutgoingClaimIndex], &r.memPool))
				} else {
					claimedEvals = append(claimedEvals, proof[src.Level].finalEvalProof[r.schedule[src.Level].FinalEvalProofIndex(r.uniqueInputIndices[wI][claimI], src.OutgoingClaimIndex)])
				}
			}
		}
	}

	return claimedEvals.Eval(&foldingCoeff), &zeroCheckLazyClaims{
		foldingCoeff: foldingCoeff,
		resources:    r,
		levelI:       levelI,
	}
}

func (r *resources) verifySumcheckLevel(levelI int, proof Proof) error {
	claimedSum, lazyClaims := r.verifyLevelSetup(levelI, proof)
	level := r.schedule[levelI].(constraint.GkrSumcheckLevel)
	return sumcheckVerify(lazyClaims, proof[levelI], claimedSum, r.circuit.ZeroCheckDegree(level), &r.transcript)
}

// singleSourceZeroCheckClaims is the prover-side claim for a single-source
// zerocheck with the eq polynomial factored out (Section 3.2 of ePrint 2024/108).
//
// When a level has exactly one claim source with evaluation point q, the standard
// round polynomial g_j(X) = Σ_h eq(q, (r₀…r_{j-1}, X, h)) · G(r₀…r_{j-1}, X, h)
// has degree d+1 (one from eq, d from the gate). Factoring out the per-variable eq
// gives g_j(X) = eq(q_j, X) · g'_j(X) where g'_j has degree d. The prover sends
// d evaluations per round instead of d+1, saving one field element per variable and
// reducing the number of gate evaluations per hypercube point from d+1 to d.
//
// The suffix eq tables eq(q_{j+1}…q_{N-1}; ·) are precomputed bottom-up and used
// read-only as weights in each round; only the input multilinears are folded.
